VALUES
  ('social-worker-moex-01311', 'social-worker', 'social-worker-moex-109-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '有關國際社會工作者協會（InternationalFederationofSocialWorkers,IFSW）2014年對社會工作 專業定義的敘述，下列何者錯誤？', '["社會正義、人權、集體責任和尊重多元是社會工作的核心原則", "社會工作是實踐為本的專業", "社會工作在促進社會變遷、社會發展和社會凝聚", "社會工作的主要理論知識基礎是社會學和心理學"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:08+00:00", "source_pdf_sha1": "32e0f8d0a2ec", "answer_pdf_sha1": "4d288512741e", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01312', 'social-worker', 'social-worker-moex-109-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '有關社區工作目標之焦點，下列何者錯誤？', '["社區工作要針對區內居民需要解決社區問題", "社區工作要聚焦在社區環境及制度改革上", "社區工作要能關注改善個人與社區的關係", "社區工作要能避開社區的權力和利益問題"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:08+00:00", "source_pdf_sha1": "32e0f8d0a2ec", "answer_pdf_sha1": "4d288512741e", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01313', 'social-worker', 'social-worker-moex-109-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '在跨專業服務的燒燙傷病房，社會工作者協助即將出院的患者銜接後續的社區醫護機構，並將患者 需求反應給相關單位或機構，和增強其持續復健動機。下列何者不是社會工作者主要的角色功能？', '["資源連結者", "情緒支持者", "教育者", "增權者"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:08+00:00", "source_pdf_sha1": "32e0f8d0a2ec", "answer_pdf_sha1": "4d288512741e", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01314', 'social-worker', 'social-worker-moex-109-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '社會工作者提供早期療育服務常運用個案管理模式，但實務運作過程往往太過於強調多重問題需 要多項資源的整合與轉介功能，而易忽略社會工作者的何種角色功能？', '["教育", "需求評量", "心理社會介入", "倡導"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:08+00:00", "source_pdf_sha1": "32e0f8d0a2ec", "answer_pdf_sha1": "4d288512741e", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01315', 'social-worker', 'social-worker-moex-109-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '關於社會工作理論與實務工作之關係，下列敘述何者正確？①社會工作者的實務經驗予以彙整分', '["理論概念提供社會工作專業人員之間相互理解的基礎", "社會工作的實 務理論基礎不會因不同的社會文化結構和社會變遷而有所差異", "運用折衷學派不需要理論基礎", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:08+00:00", "source_pdf_sha1": "32e0f8d0a2ec", "answer_pdf_sha1": "4d288512741e", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 11, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01316', 'social-worker', 'social-worker-moex-109-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '關於心理暨社會學派的敘述，下列何者正確？', '["此學派認為問題解決的短期處遇比長期處遇更為有效", "此學派主要目標在於培養與增強案主良好的問題解決態度及技術", "此學派的目標之一在於改變案主的早期生活經驗，以增加社會生活功能", "此學派認為普遍而言可以直接滿足案主生活需要來協助案主解決問題"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:08+00:00", "source_pdf_sha1": "32e0f8d0a2ec", "answer_pdf_sha1": "4d288512741e", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01317', 'social-worker', 'social-worker-moex-109-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '青少年對自己無法受同儕歡迎，歸因於沒有酷炫的手機。下列何者不是認知行為理論工作者會採 取的工作取向？', '["分析青少年需要用外物證明自己的早年生活經驗", "討論人受歡迎和使用手機廠牌之間的關聯", "討論「受歡迎」的各種可能定義", "學習建立人際關係技巧"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:08+00:00", "source_pdf_sha1": "32e0f8d0a2ec", "answer_pdf_sha1": "4d288512741e", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01318', 'social-worker', 'social-worker-moex-109-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '任務中心模式強調標的問題要清楚明確。下列何者較符合該模式所強調的「操作化任務」 （operationaltask）陳述？', '["幫助案主用更果斷的方式處理兒子的問題行為", "幫助案主更有效地準備期末考試，以免遭到學校退學", "協助案主在2天後向公司經理提出加班津貼的書面要求", "協助案主改善自己上班遲到的壞習慣"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:08+00:00", "source_pdf_sha1": "32e0f8d0a2ec", "answer_pdf_sha1": "4d288512741e", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01319', 'social-worker', 'social-worker-moex-109-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '30歲的某先生於婚後5年終盼得1子，但照顧3個月大的新生兒讓他每天晚上多次起床，常感 睡眠不足。2週前，辦公室剛搬入新辦公大樓，上個月他甫晉升一級主管，對於辦公室如何擺設， 以及對任職多年的單位中，為了發揮領導功能，如何拿捏分寸，以平衡任務取向和情感取向等， 仍感到傷腦筋。若以生活模式（Lifemodel）對於壓力來源的基本假設，下列何者不適用？', '["生活轉變", "環境壓力", "人際過程", "人格發展的缺陷"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:08+00:00", "source_pdf_sha1": "32e0f8d0a2ec", "answer_pdf_sha1": "4d288512741e", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01320', 'social-worker', 'social-worker-moex-109-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列何者不是增權觀點社會工作的實務內涵之元素？', '["倡導", "自我管理", "科層主義", "互惠性的合作協調"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:08+00:00", "source_pdf_sha1": "32e0f8d0a2ec", "answer_pdf_sha1": "4d288512741e", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
